"use strict";(self.webpackChunkredux_box=self.webpackChunkredux_box||[]).push([[385],{2723(e,s,a){a.r(s),a.d(s,{_pageData:()=>t,default:()=>l});var n=a(641);const t=JSON.parse('{"path":"/api/createModule.html","title":"createModule","lang":"en-US","frontmatter":{"title":"createModule"},"git":{"updatedTime":1778312827000,"contributors":[{"name":"Anish Kumar","username":"","email":"anish000kumar@gmail.com","commits":1}],"changelog":[{"hash":"594d62902ab92e6dc03bcfce4fa066d20824da61","time":1778312827000,"email":"anish000kumar@gmail.com","author":"Anish Kumar","message":"coveralls upgraded and docs polish"}]},"filePathRelative":"api/createModule.md"}'),o={name:"createModule.md"},l=(0,a(6262).A)(o,[["render",function(e,s,a,t,o,l){return(0,n.uX)(),(0,n.CE)("div",null,[...s[0]||(s[0]=[(0,n.Fv)('<h1 id="createmodule" tabindex="-1"><a class="header-anchor" href="#createmodule"><span>createModule</span></a></h1><h2 id="functions" tabindex="-1"><a class="header-anchor" href="#functions"><span>Functions</span></a></h2><dl><dt><a href="#generateId">generateId()</a> ⇒ <code>String</code></dt><dd><p>Generates an RFC4122-style v4 UUID. Used internally by <a href="#createModule">createModule</a> to give every module a stable, unique id so it can be looked up in the module registry regardless of the key it was mounted under in the store.</p></dd><dt><a href="#createModule">createModule(moduleObj)</a> ⇒ <code>Object</code></dt><dd><p>Wraps a plain module definition (state, mutations, sagas, selectors, dispatchers) into a redux-box module. The returned object has a unique <code>id</code> and a few helpers (<code>getName</code>, <code>getSelector</code>, <code>select</code>) that let selectors and components reference the module without hard-coding the key it was mounted under in the store.</p></dd></dl><p><a name="generateId"></a></p><h2 id="generateid-⇒-string" tabindex="-1"><a class="header-anchor" href="#generateid-⇒-string"><span>generateId() ⇒ <code>String</code></span></a></h2><p>Generates an RFC4122-style v4 UUID. Used internally by <a href="#createModule">createModule</a> to give every module a stable, unique id so it can be looked up in the module registry regardless of the key it was mounted under in the store.</p><p><strong>Kind</strong>: global function<br><strong>Returns</strong>: <code>String</code> - A new UUID, e.g. <code>&quot;3b1f0c64-0b2e-4a3f-8e65-7b6a8b4d9f10&quot;</code>.<br><a name="createModule"></a></p><h2 id="createmodule-moduleobj-⇒-object" tabindex="-1"><a class="header-anchor" href="#createmodule-moduleobj-⇒-object"><span>createModule(moduleObj) ⇒ <code>Object</code></span></a></h2><p>Wraps a plain module definition (state, mutations, sagas, selectors, dispatchers) into a redux-box module. The returned object has a unique <code>id</code> and a few helpers (<code>getName</code>, <code>getSelector</code>, <code>select</code>) that let selectors and components reference the module without hard-coding the key it was mounted under in the store.</p><p><strong>Kind</strong>: global function<br><strong>Returns</strong>: <code>Object</code> - The decorated module. In addition to the original keys it exposes:</p><ul><li><code>id</code> {String} - unique id assigned to this module.</li><li><code>getName()</code> {Function} - returns the key the module was registered under in the store.</li><li><code>getSelector()</code> {Function} - returns a <code>(state) =&gt; moduleState</code> selector.</li><li><code>select(fn)</code> {Function} - builds a memoized reselect selector over the module state.</li></ul><table><thead><tr><th>Param</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>moduleObj</td><td><code>Module</code></td><td>Plain module definition (see <a href="Module">Module</a>).</td></tr></tbody></table><p><strong>Example</strong></p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token comment">// modules/user/index.js</span></span>\n<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> createModule <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;redux-box&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"><span class="token keyword">import</span> <span class="token operator">*</span> <span class="token keyword">as</span> mutations <span class="token keyword">from</span> <span class="token string">&#39;./mutations&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"><span class="token keyword">import</span> <span class="token operator">*</span> <span class="token keyword">as</span> sagas <span class="token keyword">from</span> <span class="token string">&#39;./sagas&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"><span class="token keyword">import</span> <span class="token operator">*</span> <span class="token keyword">as</span> selectors <span class="token keyword">from</span> <span class="token string">&#39;./selectors&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"><span class="token keyword">import</span> <span class="token operator">*</span> <span class="token keyword">as</span> dispatchers <span class="token keyword">from</span> <span class="token string">&#39;./dispatchers&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"></span>\n<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token function">createModule</span><span class="token punctuation">(</span><span class="token punctuation">{</span></span>\n<span class="line">  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;user&#39;</span><span class="token punctuation">,</span></span>\n<span class="line">  <span class="token literal-property property">state</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">id</span><span class="token operator">:</span> <span class="token keyword">null</span><span class="token punctuation">,</span> <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span></span>\n<span class="line">  mutations<span class="token punctuation">,</span></span>\n<span class="line">  sagas<span class="token punctuation">,</span></span>\n<span class="line">  selectors<span class="token punctuation">,</span></span>\n<span class="line">  dispatchers<span class="token punctuation">,</span></span>\n<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Example</strong></p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token comment">// Using the `select` helper to build a memoized selector</span></span>\n<span class="line"><span class="token comment">// that is independent of the key the module was mounted under.</span></span>\n<span class="line"><span class="token keyword">const</span> getUserName <span class="token operator">=</span> userModule<span class="token punctuation">.</span><span class="token function">select</span><span class="token punctuation">(</span><span class="token parameter">user</span> <span class="token operator">=&gt;</span> user<span class="token punctuation">.</span>name<span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>',16)])])}]])}}]);